"use client"

import { Home, Chainlink, SmsTracking, MessageQuestion, Book, Briefcase } from "iconsax-react"
import { useRouter } from "next/navigation"

export default function FloatingButtons() {
    const router = useRouter()

    return (
        <div className="fixed bottom-4 right-1 flex flex-col items-end gap-3 z-50">
            <div className="group relative flex items-center">
                <div className="pointer-events-none absolute right-14 opacity-0 translate-x-2 group-hover:opacity-100 group-hover:translate-x-0 transition-all duration-200">
                    <div className="bg-black text-white text-sm px-3 py-2 rounded-lg shadow-lg whitespace-nowrap flex items-center gap-2">
                        <span>Gia sư AI</span>
                    </div>
                </div>

                <button
                    onClick={() => router.push("/giasuai")}
                    className="w-10 h-10 rounded-full bg-black text-white flex items-center justify-center shadow-lg hover:scale-105 transition"
                >
                    <SmsTracking variant="Bulk" size={23} />
                </button>
            </div>
        </div>
    )
}